  ('dietitian-moex-08559', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '學校餐廳的中央廚房，每年冷凍棒棒雞腿的需求量為800 箱。流通成本占每批貨成本的10%，每箱冷凍 棒棒雞腿的採購成本為1600元（18公斤），每次訂購所花費的成本為100元，安全庫存量為15箱，訂 貨至交貨時間平均為7天，以EOQ（Economic Order Quantity）訂購法採購，則冷凍棒棒腿的最大庫存量 為何？', '["27箱", "37箱", "47箱", "57箱"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
